use std::fs::File;
use std::io::{self, BufRead, BufReader, Write};

struct GameRecord {
    timestamp: String,
    username: String,
    action: String,
}

fn main() -> io::Result<()> {
    let input_data = "2023-10-27T10:00:00|playerA|joinn2023-10-27T10:00:05|playerB|attackn2023-10-27T10:01:10|playerA|moven2023-10-27T10:02:00|playerC|chat messagen";
    let filtered_username = "playerA";
    let output_file = "filtered_records.txt";

    let reader = BufReader::new(input_data.as_bytes());
    let mut file = File::create(output_file)?;

    for line in reader.lines() {
        let line = line?;
        let parts: Vec<&str> = line.split("|").collect();

        if parts.len() >= 2 && parts[1].contains(filtered_username) {
            writeln!(file, "Found record for {}: {}", filtered_username, line)?;
        }
    }

    Ok(())
}

use std::collections::HashMap;

struct KeyValueStore {
    data: HashMap<String, i32>,
}

impl KeyValueStore {
    fn new() -> Self {
        KeyValueStore { data: HashMap::new() }
    }

    fn insert(&mut self, key: String, value: i32) {
        self.data.insert(key, value);
    }

    fn process_map_expression(&self, input_value: i32) -> i32 {
        input_value * 2 + 1
    }

    fn process_reduce_expression(&self, first_result: i32, second_result: i32) -> i32 {
        first_result.max(second_result)
    }

    fn run_job(&mut self) -> i32 {
        let initial_value = 10;
        let mapped_value = self.process_map_expression(initial_value);

        self.insert("A".to_string(), 5);
        let reduced_result = self.process_reduce_expression(mapped_value, 20);

        reduced_result
    }
}

fn main() {
    let mut store = KeyValueStore::new();
    let final_output = store.run_job();
    println!("Final computed result: {}", final_output);
}

use std::time::Duration;

struct SensorConfig {
    id: u32,
    baud_rate: u32,
}

impl SensorConfig {
    fn new(id: u32, baud_rate: u32) -> Self {
        SensorConfig { id, baud_rate }
    }
}

fn main() {
    let sensor_identifier: u32 = 0xDEADBEEF;
    const DEVICE_VERSION: &str = "1.0.2";

    let config = SensorConfig::new(sensor_identifier, 115200);

    let input_reading: i64 = -500;
    let calculated_offset: i32 = 10;

    // Demonstrating usage of constant and derived values
    println!("Firmware initialized for ID: 0x{:X}", config.id);
    println!("Version: {}", DEVICE_VERSION);

    let final_value = (input_reading / 100) + (calculated_offset as i64);

    println!("Processed reading value: {}", final_value);

    let startup_delay = Duration::from_millis(500);
    println!("Will wait for approximately {:?}", startup_delay);
}
